//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String types;
    String repository;
    String author;
    String license;
    List<String> files;
    Scripts scripts;
    Xo xo;
    DevDependencies devDependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.types,
        required this.repository,
        required this.author,
        required this.license,
        required this.files,
        required this.scripts,
        required this.xo,
        required this.devDependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        types: json["types"],
        repository: json["repository"],
        author: json["author"],
        license: json["license"],
        files: List<String>.from(json["files"].map((x) => x)),
        scripts: Scripts.fromJson(json["scripts"]),
        xo: Xo.fromJson(json["xo"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "types": types,
        "repository": repository,
        "author": author,
        "license": license,
        "files": List<dynamic>.from(files.map((x) => x)),
        "scripts": scripts.toJson(),
        "xo": xo.toJson(),
        "devDependencies": devDependencies.toJson(),
    };
}

class DevDependencies {
    String chai;
    String jest;
    String xo;

    DevDependencies({
        required this.chai,
        required this.jest,
        required this.xo,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        chai: json["chai"],
        jest: json["jest"],
        xo: json["xo"],
    );

    Map<String, dynamic> toJson() => {
        "chai": chai,
        "jest": jest,
        "xo": xo,
    };
}

class Scripts {
    String pretest;
    String test;

    Scripts({
        required this.pretest,
        required this.test,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        pretest: json["pretest"],
        test: json["test"],
    );

    Map<String, dynamic> toJson() => {
        "pretest": pretest,
        "test": test,
    };
}

class Xo {
    Rules rules;

    Xo({
        required this.rules,
    });

    factory Xo.fromJson(Map<String, dynamic> json) => Xo(
        rules: Rules.fromJson(json["rules"]),
    );

    Map<String, dynamic> toJson() => {
        "rules": rules.toJson(),
    };
}

class Rules {
    int complexity;
    int maxDepth;
    int noDivRegex;

    Rules({
        required this.complexity,
        required this.maxDepth,
        required this.noDivRegex,
    });

    factory Rules.fromJson(Map<String, dynamic> json) => Rules(
        complexity: json["complexity"],
        maxDepth: json["max-depth"],
        noDivRegex: json["no-div-regex"],
    );

    Map<String, dynamic> toJson() => {
        "complexity": complexity,
        "max-depth": maxDepth,
        "no-div-regex": noDivRegex,
    };
}
